"""
Recorder engine for 15-minute, 30-minute, and 1-hour bar persistence.

This module follows the same event/queue pattern used by
vnpy.app.data_recorder.engine. The difference is that 15m and 30m bars
are stored in dedicated MongoDB collections, because the default vn.py
Interval enum only distinguishes minute/hour/day and cannot uniquely
identify multiple minute windows in the shared bar collection.
"""

from copy import copy
from datetime import datetime
from enum import Enum
from queue import Empty
import traceback
from typing import Dict, Sequence

from mongoengine.context_managers import switch_collection

from vnpy.trader.constant import Exchange, Interval
from vnpy.trader.database import database_manager
from vnpy.trader.database.database_mongo import DbBarData, MongoManager
from vnpy.trader.object import BarData
from vnpy.trader.utility import BarGenerator

from .engine import RecorderEngine


WINDOW_TASKS: Dict[int, str] = {
    15: "bar_15m",
    30: "bar_30m",
}


class WindowBarPipeline:
    """Wrap one BarGenerator so minute bars feed back into update_bar()."""

    def __init__(self, window: int, on_window_bar, interval: Interval = Interval.MINUTE):
        self.generator = BarGenerator(self.on_bar, window, on_window_bar, interval)

    def on_bar(self, bar: BarData):
        self.generator.update_bar(bar)

    def update_tick(self, tick):
        self.generator.update_tick(tick)


class MultiWindowBarGenerator:
    """Dispatch each incoming tick to multiple window pipelines."""

    def __init__(self, pipelines: Dict[int, WindowBarPipeline]):
        self.pipelines = pipelines

    def update_tick(self, tick):
        for pipeline in self.pipelines.values():
            pipeline.update_tick(tick)


class WindowBarRecorderEngine(RecorderEngine):
    """
    Recorder engine that aggregates tick data into 15m, 30m, and 1h bars.

    The base RecorderEngine already handles:
    1. subscription management
    2. tick recording
    3. queue-based database writes

    This subclass keeps the original 1-hour persistence and adds
    automatic 15m/30m persistence for the same subscribed symbols.
    """

    def __init__(self, main_engine, event_engine):
        super().__init__(main_engine, event_engine)
        self.write_log("已启用15分钟、30分钟和1小时K线自动落库")

    def run(self):
        """Consume queued save tasks."""
        while self.active:
            try:
                task_type, data = self.queue.get(timeout=1)

                if task_type == "tick":
                    database_manager.save_tick_data([data])
                elif task_type == "bar":
                    database_manager.save_bar_data([data])
                elif task_type == WINDOW_TASKS[15]:
                    self.save_window_bar_data(data, 15)
                elif task_type == WINDOW_TASKS[30]:
                    self.save_window_bar_data(data, 30)
            except Empty:
                continue
            except Exception:
                msg = "窗口K线落库失败：\n{}".format(traceback.format_exc())
                self.write_log(msg)

    def get_bar_generator(self, vt_symbol: str):
        """
        Return the root dispatcher that converts ticks into 15m/30m/1h bars.

        Each target window keeps its own BarGenerator instance so the
        generator retains the same tick-driven behavior as the original
        recorder implementation.
        """
        bg = self.bar_generators.get(vt_symbol, None)

        if not bg:
            pipelines = {
                15: WindowBarPipeline(15, self.record_15min_bar),
                30: WindowBarPipeline(30, self.record_30min_bar),
                60: WindowBarPipeline(1, self.record_bar, Interval.HOUR),
            }
            bg = MultiWindowBarGenerator(pipelines)
            self.bar_generators[vt_symbol] = bg

        return bg

    def record_15min_bar(self, bar: BarData):
        """Queue one 15-minute bar for persistence."""
        self.queue.put((WINDOW_TASKS[15], copy(bar)))

    def record_30min_bar(self, bar: BarData):
        """Queue one 30-minute bar for persistence."""
        self.queue.put((WINDOW_TASKS[30], copy(bar)))

    @staticmethod
    def to_update_param(data: BarData) -> dict:
        """Convert dataclass fields to mongoengine update parameters."""
        return {
            "set__" + key: value.value if isinstance(value, Enum) else value
            for key, value in data.__dict__.items()
        }

    def save_window_bar_data(self, bar: BarData, window: int):
        """
        Save minute-window bars to dedicated MongoDB collections.

        Examples:
        - rb2501.SHFE.15m
        - rb2501.SHFE.30m
        """
        if not isinstance(database_manager, MongoManager):
            raise RuntimeError(
                "WindowBarRecorderEngine requires MongoDB because vn.py's "
                "default bar schema cannot distinguish 15m and 30m bars."
            )

        updates = self.to_update_param(bar)
        updates.pop("set__gateway_name", None)
        updates.pop("set__vt_symbol", None)

        collection_name = f"{bar.symbol}.{bar.exchange.value}.{window}m"

        with switch_collection(DbBarData, collection_name):
            (
                DbBarData.objects(
                    symbol=bar.symbol,
                    exchange=bar.exchange.value,
                    interval=bar.interval.value,
                    datetime=bar.datetime,
                ).update_one(upsert=True, **updates)
            )

    def load_window_bar_data(
        self,
        symbol: str,
        exchange: Exchange,
        window: int,
        start: datetime,
        end: datetime,
    ) -> Sequence[BarData]:
        """Load 15m/30m bars from the dedicated MongoDB collections."""
        if not isinstance(database_manager, MongoManager):
            raise RuntimeError(
                "WindowBarRecorderEngine requires MongoDB because vn.py's "
                "default bar schema cannot distinguish 15m and 30m bars."
            )

        if window not in WINDOW_TASKS:
            raise ValueError(f"Unsupported window: {window}")

        collection_name = f"{symbol}.{exchange.value}.{window}m"

        with switch_collection(DbBarData, collection_name):
            records = DbBarData.objects(
                symbol=symbol,
                exchange=exchange.value,
                interval=Interval.MINUTE.value,
                datetime__gte=start,
                datetime__lt=end,
            )
            return [record.to_bar() for record in records]
